import React, { useEffect, useState } from "react";
import Sidebar from "../../components/Sidebar";
import { getAllProjects } from "../../api/api";

const ManageProjects = () => {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const res = await getAllProjects();
      setProjects(res.data);
      setLoading(false);
    } catch (error) {
      console.log(error);
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-100">

      {/* SIDEBAR */}
      <Sidebar />

      {/* MAIN WRAPPER */}
      <div className="flex-1 ml-64">

        {/* TOP BAR */}
        <div className="bg-white border-b px-8 py-4 shadow-sm">
          <h2 className="text-lg font-semibold text-gray-700">
            Projects
          </h2>
        </div>

        {/* CONTENT AREA */}
        <div className="max-w-6xl mx-auto px-8 py-8">

          <h1 className="text-3xl font-bold text-gray-800 mb-8">
            All Projects
          </h1>

          {loading ? (
            <div className="text-gray-500">Loading projects...</div>
          ) : projects.length === 0 ? (
            <div className="text-gray-500">No Projects Found</div>
          ) : (
            <div className="space-y-6">

              {projects.map((project) => (
                <div
                  key={project.id}
                  className="bg-white rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition p-6"
                >

                  {/* HEADER */}
                  <div className="flex justify-between items-start">

                    <div>
                      <h2 className="text-xl font-semibold text-gray-800">
                        {project.title}
                      </h2>

                      <p className="text-gray-500 mt-1 text-sm">
                        {project.description}
                      </p>

                      {/* SKILLS */}
                      {project.skills && (
                        <div className="flex flex-wrap gap-2 mt-3">
                          {project.skills.map((skill, index) => (
                            <span
                              key={index}
                              className="bg-gray-100 text-gray-600 px-3 py-1 rounded-full text-xs font-medium"
                            >
                              {skill}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>

                    {/* STATUS BADGE */}
                    <span
                      className={`px-3 py-1 rounded-full text-xs font-semibold capitalize ${
                        project.status === "completed"
                          ? "bg-gray-200 text-gray-600"
                          : project.status === "in-progress"
                          ? "bg-blue-100 text-blue-600"
                          : "bg-green-100 text-green-600"
                      }`}
                    >
                      {project.status || "open"}
                    </span>
                  </div>

                  {/* FOOTER */}
                  <div className="flex justify-between items-center mt-6 pt-4 border-t text-sm text-gray-500">

                    <div className="flex items-center gap-8">

                      <div className="flex items-center gap-2">
                        <span>💰</span>
                        <span className="font-medium text-gray-700">
                          ₹{project.budget}
                        </span>
                      </div>

                      <div className="flex items-center gap-2">
                        <span>📅</span>
                        <span>
                          {project.deadline || "Apr 20, 2026"}
                        </span>
                      </div>

                      <div className="flex items-center gap-2">
                        <span>🏢</span>
                        <span>
                          {project.company || "Company Name"}
                        </span>
                      </div>

                    </div>

                    <div className="text-teal-600 font-semibold">
                      {project.proposals || 0} proposals
                    </div>

                  </div>

                </div>
              ))}

            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default ManageProjects;
